import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    if len(unvisited_customers) == 0:
        return None  # No more customers to visit

    distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])

    truck_impact_scores = []
    for customer in unvisited_customers:
        other_truck_distances = np.array([distance(truck_pos, customer) for truck_pos in all_truck_pos if not np.array_equal(truck_pos, cur_truck_pos)])
        if len(other_truck_distances) > 0:
            truck_impact_scores.append(np.sum(1 / other_truck_distances))
        else:
            truck_impact_scores.append(0)

    # Score function combining distance and normalized truck impact
    alpha = 0.2
    combined_scores = distances + alpha * np.array(truck_impact_scores)

    best_node = np.argmin(combined_scores)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    if len(unvisited_customers) == 0:
        return None  # No more customers to visit

    distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])

    # Anticipate future utility
    future_utility_scores = []
    for customer in unvisited_customers:
        projected_returns = [distance(customer, other_customer) for other_customer in unvisited_customers if not np.array_equal(customer, other_customer)]
        future_utility_scores.append(np.mean(projected_returns) if projected_returns else 0)

    # Adjusted metric combining current distance and future utility (with a tuning parameter for utility)
    combined_scores = distances + 0.3 * np.array(future_utility_scores)

    best_node = np.argmin(combined_scores)

    return best_node
